INSERT INTO public.photos VALUES (23634, 'Visita de Alfonso XII 1882', 'A.M.Z. Sign. 0908. Monumentos conmemorativos con motivo de la visita del rey Alfonso XII y su esposa la reina Cristina de Habsburgo a Zaragoza. Tres engalanamientos para Zaragoza ante la visita del rey Borbâ”śâ”‚n y su esposa, Cristina de Habsburgo. El primero, un Arco de Triunfo sito en el paseo de Santa Engracia; el segundo, en la entrada del hospicio Provincial y el tercero, ornato neoarâ”śĂ­bigo en la puerta de un cuartel sin identificar.', 1882, 1882, 1882, 'Siglo XIX', 'CENTRO', 41.65365100, -0.89044800, '0101000020E6100000473CD9CD8C7EECBFB5FF01D6AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672229740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672229740.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672229740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23923, 'Cuartel de Sangenis 1963', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Agosto 1963. "Vista general de una edificaciâ”śâ”‚n." Concretamente, se trata del Centro de Especialidades "Ramâ”śâ”‚n y Cajal", a la derecha, junto al Paseo de Marâ”śÂˇa Agustâ”śÂˇn. A su izquierda se levantarâ”śĂ­, tres aâ”śâ–’os despuâ”śÂ®s, la Delegaciâ”śâ”‚n Provincial de Trabajo. Mientras tanto, desde la altura del alto bloque de viviendas inmediato a los antiguos talleres de oficios del hospicio provincial, u Hogar Pignatelli, podemos contemplar una buena perspectiva del inmenso Cuartel de Sangenis, o de Pontoneros, y el Hospital de Nuestra Seâ”śâ–’ora de Gracia. A la izquierda, por encima de los tejados sobresale la cupulilla de la iglesia de los Escolapios.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65246500, -0.88831500, '0101000020E6100000CC7A3194136DECBF6F641EF983D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15033159208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15033159208.webp', 'https://www.flickr.com/photos/zaragozaantigua/15033159208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24056, 'Avenida Câ”śÂ®sar Augusto 2005', 'Foto: Juan Carlos Arcos. 11 de octubre de 2005. Un elefante asiâ”śĂ­tico del Circo Mundial desayuna frutas y verduras junto al hotel Meliâ”śĂ­ Zaragoza. A la derecha, grâ”śâ•‘a y andamios de la obra de remodelaciâ”śâ”‚n/demoliciâ”śâ”‚n del Teatro Fleta, paralizada en 2003. En 2013, ante la prolongada situaciâ”śâ”‚n de parâ”śĂ­lisis, el andamio fue retirado. Y en 2015, los circos con animales dejaron de visitar la ciudad. Fuente: Heraldo de Aragâ”śâ”‚n.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65138400, -0.88609400, '0101000020E610000081D1E5CDE15AECBF9F91088D60D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31674976752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31674976752.webp', 'https://www.flickr.com/photos/zaragozaantigua/31674976752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24074, 'Palacio de Cristal 1931', 'Imagen de la suntuosa fachada del Palacio de Cristal, sito en el recinto del Iris Park, con entrada principal por la calle de Ramâ”śâ”‚n y Cajal. Su denominaciâ”śâ”‚n venâ”śÂˇa dada porque en sus altas paredes se abrâ”śÂˇa una enorme cantidad de ventanales y vidrieras, lo que le convertâ”śÂˇa en un escenario â”śâ•‘nico para la celebraciâ”śâ”‚n de diversos eventos festivos con gran afluencia de pâ”śâ•‘blico. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65166000, -0.88547400, '0101000020E61000006DAAEE91CD55ECBF410E4A9869D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36610510405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36610510405.webp', 'https://www.flickr.com/photos/zaragozaantigua/36610510405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24516, 'Lavadero de Castellvâ”śÂˇ 1931', 'Imagen capturada desde cierta altura con el panorama del lavadero de Castellvâ”śÂˇ al poco tiempo de su cierre. Su enorme extensiâ”śâ”‚n, sobre todo para la zona de secadero de ropa al aire, estaba delimitada por las calles de Ramâ”śâ”‚n y Cajal, de la Soberanâ”śÂˇa Nacional, y del Azoque. En la imagen, a la izquierda, parte del antiguo hospital Militar anexo a la iglesia de Santiago. Al fondo, traseras de edificios de vivienda recayentes a la calle de la Biblioteca, y a la del Azoque. Sobre este solar se levantarâ”śÂˇa, poco despuâ”śÂ®s, el complejo recreativo del Iris Park, inaugurado ese mismo aâ”śâ–’o. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65166000, -0.88547400, '0101000020E61000006DAAEE91CD55ECBF410E4A9869D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35180440752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35180440752.webp', 'https://www.flickr.com/photos/zaragozaantigua/35180440752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24875, 'Piscina y torres 1970', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo 1970. Desde la piscina del nuevo Hotel Corona de Aragâ”śâ”‚n las vistas son tremendas. En la imagen, sin pretenderlo, despuntan el remate de la câ”śâ•‘pula de Santiago el Mayor, el torreâ”śâ”‚n del Banco de Aragâ”śâ”‚n, la torre de la Seo y su cimborrio, San Gil... Y abajo, la nueva avenida de Câ”śÂ®sar Augusto.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65146200, -0.88622800, '0101000020E6100000689599D2FA5BECBF1B4B581B63D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14753647307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14753647307.webp', 'https://www.flickr.com/photos/zaragozaantigua/14753647307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24896, 'Delegaciâ”śâ”‚n Provincial de Trabajo 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho 24/12/1966. Antigua Delegaciâ”śâ”‚n Provincial de Trabajo de Zaragoza, en la calle Doctor Fleming con vistas a Marâ”śÂˇa Agustâ”śÂˇn, desde donde estâ”śĂ­ hecha la foto. El edificio acaba de ser inaugurado, formando un conjunto con el del Hospital Ramâ”śâ”‚n y Cajal, ambos del arquitecto Fernando Garcâ”śÂˇa Mercadal. Al fondo a la izquierda, torre de San pablo. A la derecha, detrâ”śĂ­s del Hospital de Nuestra Seâ”śâ–’ora de Gracia, la câ”śâ•‘pula de la iglesia de Santiago.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65125700, -0.88938700, '0101000020E6100000079ACFB9DB75ECBF4225AE635CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15211673115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15211673115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15211673115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25472, 'Propiedades de la Diputaciâ”śâ”‚n 1953', 'Plano de edificios y terrenos propiedad de la Diputaciâ”śâ”‚n de Zaragoza, noviembre de 1953. Fuente: Archivo DPZ.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65277600, -0.88973200, '0101000020E6100000AC8C463EAF78ECBF8ECEF9298ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24313701002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24313701002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24313701002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25488, 'P.â”¬â•‘ de Marâ”śÂˇa Agustâ”śÂˇn c.1961', 'Imagen capturada posiblemente desde la altura del nâ”¬â•‘ 9 del paseo de Marâ”śÂˇa Agustâ”śÂˇn, esquinero con la calle del Capitâ”śĂ­n Esponera, con una interesante vista parcial de la zona delimitada entre el paseo, la nueva calle del Doctor Fleming y el Hogar Pignatelli. En primer tâ”śÂ®rmino, huerta de las MM. Carmelitas de la Encarnaciâ”śâ”‚n y del Hospital Provincial. En el centro, edificios inmediatos al ya derribado Anfiteatro, Sala de Disecciâ”śâ”‚n y Capilla para Cadâ”śĂ­veres del Hospital Provincial. Enfrente, Talleres del Hogar Pignatelli y los modernos y rectangulares bloques edilicios para funcionarios. Tras ellos, el Hogar Pignatelli y, parcialmente, la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana. Al fondo del paseo, el Grupo Escolar Joaquâ”śÂˇn Costa y las viviendas para militares de la confluencia con Anselmo Clavâ”śÂ®.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65118400, -0.88954800, '0101000020E6100000541C075E2D77ECBFD8D64FFF59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43601516425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43601516425.webp', 'https://www.flickr.com/photos/zaragozaantigua/43601516425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25701, 'Sala de disecciâ”śâ”‚n 1873', '"Plano general de la huerta alta del hospital provincial, planta, alzado y secciones del Anfiteatro Sala de disecciâ”śâ”‚n y capilla para cadâ”śĂ­veres", Julio Ferrâ”śĂ­n, Zaragoza, 1873. En las inmediaciones del Hospital Provincial se levantâ”śâ”‚ este pequeâ”śâ–’o edificio en 1873, con su teatro anatâ”śâ”‚mico y su capilla. En â”śÂ®l trabajâ”śâ”‚ Santiago Ramâ”śâ”‚n y Cajal. Fue demolido en 1958. El plano general (abajo) estâ”śĂ­ orientado de sur a norte, con el paseo de la Ronda (hoy Marâ”śÂˇa Agustâ”śÂˇn) indicado arriba. La ubicaciâ”śâ”‚n actual serâ”śÂˇa la calle del Doctor Fleming, en su tramo mâ”śĂ­s cercano al paseo. Fuente: Archivo DPZ.', 1873, 1873, 1873, 'Siglo XIX', 'CENTRO', 41.65158300, -0.88950600, '0101000020E610000099107349D576ECBF96D05D1267D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21785140679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21785140679.webp', 'https://www.flickr.com/photos/zaragozaantigua/21785140679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26058, 'Vista aâ”śÂ®rea Vâ”śÂˇa Imperial c.1969', 'Vista aâ”śÂ®rea centrada en la Vâ”śÂˇa Imperial, con la Puerta del Carmen abajo y el Teatro Fleta en el centro. Al fondo, el Coso Alto. Fuente visual: foto Pedro Marco.', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65145900, -0.88595700, '0101000020E61000005531957EC259ECBFAAD72D0263D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33569037491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33569037491.webp', 'https://www.flickr.com/photos/zaragozaantigua/33569037491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23018, 'Pl. del Ecce Homo c.1998', 'Imagen capturada en la plaza del Ecce Homo y centrada en los abandonados edificios de los nâ”śâ•‘meros 6 y 7 de ese vial, inmediatos a la imprenta de Tomâ”śĂ­s Blasco (nâ”¬â•‘ 8). A la izquierda, solares de los ya derribados nâ”śâ•‘meros 5 y 4, esquinero â”śÂ®ste â”śâ•‘ltimo con la calle de Galo Ponte, antigua de la Audiencia. Enfrente a todos ellos, vista parcial de los andamios de remodelaciâ”śâ”‚n del nâ”¬â•‘ 3 como nueva sede de la Escuela Universitaria de Turismo de Zaragoza (ETUZ). Fuente visual: AMZ.', 1998, 1998, 1998, 'Anos 90', 'CENTRO', 41.65467100, -0.88301400, '0101000020E6100000E61F7D93A641ECBFDF516342CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40710585122.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40710585122.webp', 'https://www.flickr.com/photos/zaragozaantigua/40710585122/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23132, 'Plaza Ecce Homo 2007', 'Foto: Juan Carlos Arcos. Vista del edificio de la Imprenta Blasco, en la plaza del Ecce Homo 8, esquina con la calle del Paraâ”śÂˇso (derecha), en octubre de 2007. Este inmueble con ornamentos neogâ”śâ”‚ticos fue levantado en dos fases, segâ”śâ•‘n proyecto de Teodoro Râ”śÂˇos: en 1924 (fachada a Ecce Homo) y en 1938 (chaflâ”śĂ­n y ala derecha). Fue adquirido por el Ayuntamiento en 2002, con la intenciâ”śâ”‚n de que albergase un museo de la imprenta. El bloque de la derecha fue derribado ese mismo mes. Fuente: Heraldo de Aragâ”śâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65466600, -0.88321000, '0101000020E61000005001309E4143ECBFCDE67118CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31694772074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31694772074.webp', 'https://www.flickr.com/photos/zaragozaantigua/31694772074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21231, 'Muralla medieval 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 35, Zaragoza 1908 - Centenario de los Sitios", 1907. "Tapia aspillerada de San Agustâ”śÂˇn. Siendo el convento de San Agustâ”śÂˇn uno de los puntos mâ”śĂ­s atacados desde las baterâ”śÂˇas francesas inmediatas al Huerva, los altos muros que cercaban su huerta, fueron aspillerados para la defensa de toda aquella parte de la ciudad, por donde los invasores intentaron repetidamente su entrada." Trenque en la muralla medieval, actualmente conservado entre los nâ”śâ•‘meros 53 y 55 de la calle Asalto de Zaragoza. En el momento de tomar la foto, el lugar correspondâ”śÂˇa a las traseras del convento de las Capuchinas. Fuente: www.pasapues.es/antiguas/exposicion1908/zaragoza190835.php', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64925000, -0.87275800, '0101000020E6100000D7506A2FA2EDEBBFC976BE9F1AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19240864666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19240864666.webp', 'https://www.flickr.com/photos/zaragozaantigua/19240864666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21318, 'Calle La Torre 1908', 'Calle de La Torre, en su entonces â”śâ•‘ltimo tramo, bajando hasta la de Manuela Sancho, en la que terminaba. El edificio de la izquierda es la fâ”śĂ­brica de Averly, Montaut y Garcâ”śÂˇa, con razâ”śâ”‚n social en las calles de La Torre 23 y Manuela Sancho 27. Su propietario â”śâ•‘nico en 1908 era Josâ”śÂ® Garcâ”śÂˇa Dâ”śÂˇaz, y producâ”śÂˇa telas metâ”śĂ­licas, ademâ”śĂ­s de comercializar piedras de molino importadas de Francia. La compaâ”śâ–’â”śÂˇa se habâ”śÂˇa constituido en 1877, con Antonio Averly como socio, pero ya en 1880 â”śÂ®ste trasladâ”śâ”‚ sus actividades a la Fundiciâ”śâ”‚n Averly de Campo Sepulcro. Fuente visual: Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64958300, -0.87334800, '0101000020E610000040DD408177F2EBBFCF84268925D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40482429784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40482429784.webp', 'https://www.flickr.com/photos/zaragozaantigua/40482429784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21445, 'Calle de La Torre c.1912', 'Imagen capturada en el â”śâ•‘ltimo tramo de la calle de la Torre (antigua de la Subida del Gato) y centrada en el soleado inmueble del nâ”¬â•‘ 23, esquinero con el nâ”¬â•‘ 27 de la calle de Manuela Sancho (antigua del Pabostre), donde estaba radicada desde 1877 la fâ”śĂ­brica de piedras de molino y telas metâ”śĂ­licas de Averly, Montaut y Garcâ”śÂˇa, que desde 1903 era propiedad en solitario de Josâ”śÂ® Garcâ”śÂˇa Dâ”śÂˇaz. Un carro tirado por caballerâ”śÂˇa carga unos metros lineales de tela metâ”śĂ­lica, mientras los trajineros posan en la puerta de la factorâ”śÂˇa. Destaca el final de la calle de la Torre, que desemboca en la de Manuela Sancho, cuyos inmuebles nâ”¬â•‘ 32-34 figuran al fondo. Tras siglos con este trazado urbanâ”śÂˇstico, tiempo despuâ”śÂ®s la calle de la Torre serâ”śÂˇa prolongada hasta la calle del Asalto, cuyos â”śĂ­rboles emergen levemente sobre el horizonte.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64957900, -0.87335900, '0101000020E61000003A5AD5928EF2EBBF8E95986725D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49949988797.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49949988797.webp', 'https://www.flickr.com/photos/zaragozaantigua/49949988797/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21447, 'Calle de Manuela Sancho c.1912', 'Imagen capturada en la calle de Manuela Sancho y centrada en inmueble del nâ”¬â•‘ 27, esquinero con la calle de la Torre, donde estaba radicada la fâ”śĂ­brica de piedras de molino y telas metâ”śĂ­licas de Averly, Montaut y Garcâ”śÂˇa. La escena representa la maniobra de carga mediante polea de una piedra de molino en un carro. A la derecha y fuera de plano se encontraba el convento de las capuchinas. Hacia el fondo, la calle curvea hasta la plazuela de las Eras, pasando por la calle de las Eras y la de Alcalâ”śĂ­.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64946600, -0.87320900, '0101000020E6100000E754320054F1EBBF95EEAEB321D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49955288947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49955288947.webp', 'https://www.flickr.com/photos/zaragozaantigua/49955288947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21824, 'Râ”śÂˇo Huerva 1933', 'Aspecto del râ”śÂˇo Huerva durante la crecida de principios del mes de junio, a su paso por la calle del Asalto, en una imagen capturada desde el puente de San Josâ”śÂ®. A la izquierda, muros traseros del Corral de Abastos de Intendencia militar. Al fondo, tras la chimenea de la central de Elâ”śÂ®ctricas Reunidas de Zaragoza, y el Cuartel de la Tercera Comandancia de Intendencia. Hemos introducido una referencia aproximada, en distintivo color verde, a la lâ”śÂˇnea de la antigua ribera que el desbordamiento de caudal se llevâ”śâ”‚ consigo aguas abajo, hasta el Ebro. Fuente visual: foto Palacio, en "Diario Ahora" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64833000, -0.87339500, '0101000020E61000006DAD2F12DAF2EBBF0282397AFCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32191582830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32191582830.webp', 'https://www.flickr.com/photos/zaragozaantigua/32191582830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22205, 'Calle de la Torre 1951', 'Despejada imagen de la adoquinada calle de la Torre capturada desde su desemboque en descenso en la calle de Manuela Sancho (antigua del Pabostre), donde originalmente terminaba. A la derecha, en la que fuera zona de las Eras de San Agustâ”śÂˇn, fachadas de los desaparecidos inmuebles de los nâ”śâ•‘meros 23, 21, 19 y 17. Al fondo, el desaparecido nâ”¬â•‘ 16, camino al arranque de esta calle desde la de Cantâ”śÂˇn y Gamboa. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64953300, -0.87336800, '0101000020E610000007EFAB72A1F2EBBF1D56B8E523D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38244734061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38244734061.webp', 'https://www.flickr.com/photos/zaragozaantigua/38244734061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22819, 'Calle del Asalto 1973', 'Inâ”śÂ®dita imagen capturada en la calle del Asalto a la altura de las traseras del convento de las Madres clarisas capuchinas que entre 1877 y 1973 estuvo ubicado en la calle de Manuela Sancho. El amplio terreno de ese convento fue vendido al mejor postor, que tras el preceptivo derribo promoviâ”śâ”‚ la construcciâ”śâ”‚n de unos modernos bloques de viviendas. El muro perimetral recayente a la calle del Asalto, resto de la antigua muralla de ladrillo y adobe levantada en tiempos de la Saraqusta musulmana, y reforzada posteriormente, presenta una lâ”śĂ­pida instalada en 1908 a instancias del Ayuntamiento que recuerda que durante los asedios de 1808-1809 aquâ”śÂˇ estuvo ubicada la "baterâ”śÂˇa alta de Palafox", posiciâ”śâ”‚n artillera donde encontrâ”śâ”‚ la muerte el comandante de ingenieros militares Antonio Sangenis. Este hecho preservâ”śâ”‚ milagrosamente este muro del integral derribo de todas las dependencias conventuales. Al fondo y a la derecha sobresale el moderno bloque incrustado en la manzana entre la calle de Manuela Sancho, la plaza de las Eras y la calle de Alcalâ”śĂ­, y que poco despuâ”śÂ®s serâ”śÂˇa eclipsado por los bloques aquâ”śÂˇ construidos. En primer tâ”śÂ®rmino, un Seat 1500 en su popular versiâ”śâ”‚n como taxi.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64912200, -0.87262900, '0101000020E6100000615111A793ECEBBF9B8E006E16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51622307225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51622307225.webp', 'https://www.flickr.com/photos/zaragozaantigua/51622307225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22893, 'Canâ”śâ”‚dromo c.1982', 'Foto del canâ”śâ”‚dromo de Zaragoza en los aâ”śâ–’os 80. Estaba situado en Miguel Servet 1, interior: el actual parque de Villafeliche, vulgo del Canâ”śâ”‚dromo, en la calle de Salvador de Madariaga, junto al râ”śÂˇo Huerva. Al fondo se puede ver la torre de la iglesia de San Miguel.', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64836000, -0.87435700, '0101000020E6100000E2EA0088BBFAEBBF6C04E275FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20424249245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20424249245.webp', 'https://www.flickr.com/photos/zaragozaantigua/20424249245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23058, 'Parque de Villafeliche 1994', 'A mediados de la dâ”śÂ®cada de los noventa se llevâ”śâ”‚ a cabo la transformaciâ”śâ”‚n de la ribera del râ”śÂˇo Huerva a su paso por Zaragoza en un corredor verde denominado Parque Lineal del Râ”śÂˇo Huerva, un proyecto global que sumaba una serie de parques entre los que se encuentra el llamado parque de Villafeliche, trazado donde estuviera el antiguo Canâ”śâ”‚dromo. En la imagen, tareas de limpieza en una captura de esta zona donde al fondo y a la izquierda se destaca el inmueble de la calle de la Torre esquinero con la del Asalto. A la derecha, las instalaciones de ERZ-Endesa y el Hâ”śĂ­bitat Don 2000.', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64860800, -0.87390600, '0101000020E6100000D1E638B709F7EBBF45F6419605D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50451149326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50451149326.webp', 'https://www.flickr.com/photos/zaragozaantigua/50451149326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24975, 'Vivero de la Puerta Quemada 1865', 'Plano del vivero de la Puerta Quemada, Antonio Berbegal, Zaragoza, 1865. Aspecto de la plantaciâ”śâ”‚n municipal de acacias y olmos en el solar triangular de los viveros municipales de la Puerta Quemada, en 1920 ferial de ganado, luego almacâ”śÂ®n de intendencia del ejâ”śÂ®rcito "Corral de la Leâ”śâ–’a", y actual parque del mismo nombre (antes "de la Mancomunidad de Aragâ”śâ”‚n"), primera actuaciâ”śâ”‚n de la "Operaciâ”śâ”‚n cuarteles", en 1975. Arriba, el entonces paseo de la Mina, hoy calle de Asalto. Fuente: AMZ.', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.64879200, -0.87238400, '0101000020E61000009EB7B1D991EAEBBF06F4C29D0BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20411112124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20411112124.webp', 'https://www.flickr.com/photos/zaragozaantigua/20411112124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20924, 'Convento de San Francisco hacia 1500', '"Das Franziskaner Kloster in Saragossa", fotografâ”śÂˇa realizada por Max Skladanowsky hacia 1890, coloreada luego a mano, en la que captura un dibujo de autor desconocido que pretende recrear el hipotâ”śÂ®tico claustro del Real convento de San Francisco de Zaragoza, situado entre la estrecha calle del Hospital y el Coso de Carabaceros. La nostalgia del pasado medieval, impostada como tendencia intelectual decimonâ”śâ”‚nica en Europa, derivâ”śâ”‚ en la "recuperaciâ”śâ”‚n" virtual de elementos arquitectâ”śâ”‚nicos desaparecidos del medievo, como este convento levantado en el siglo XIII, con posteriores e importantes reformas y ampliaciones, que fue muy afectado por los conflictos bâ”śÂ®licos de 1808-1809, y cuya enorme extensiâ”śâ”‚n luego fue, bien vendida a particulares, bien convertida en solar sobre el que construir las dependencias de la Diputaciâ”śâ”‚n Provincial. Los hermanos Skladanowsky (este Max, y Emil), fueron los pioneros del cine en Alemania con su proyector "Bioskop" en 1895, en el Teatro "Wintergarten" de Berlâ”śÂˇn, unas semanas antes que otros hermanos franceses, de apellido Lumiâ”śÂżre, hicieran lo propio en el Gran Cafâ”śÂ® de Parâ”śÂˇs. Fuente visual: www.bild.bundesarchiv.de/', 1500, 1500, 1500, 'Siglo XIX', 'CENTRO', 41.65247300, -0.88168500, '0101000020E6100000D8F50B76C336ECBFF2423A3C84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20547463171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20547463171.webp', 'https://www.flickr.com/photos/zaragozaantigua/20547463171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21013, 'Coso Medio 1860', 'Recreaciâ”śâ”‚n estilizada del templete o torreâ”śâ”‚n â”śĂ­rabe erigido con motivo de la visita de la reina Isabel II a la ciudad. Fuente: www.mecd.gob.es/', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65267200, -0.88129900, '0101000020E61000008EEBDFF59933ECBFE9818FC18AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18835474358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18835474358.webp', 'https://www.flickr.com/photos/zaragozaantigua/18835474358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21021, 'Pl. de la Constituciâ”śâ”‚n 1868', 'Grabado de Urrabieta en el que se representa una manifestaciâ”śâ”‚n de zaragozanas contra el reclutamiento de las quintas con destino a â”śĂĽfrica, ante el edificio de la Diputaciâ”śâ”‚n Provincial de Zaragoza. En carteles y banderas se puede leer: "Abajo las quintas", "Abajo los Borbones" y "Repâ”śâ•‘blica Federal Sufragista". Fuente: www.akg-images.co.uk/', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20689438908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20689438908.webp', 'https://www.flickr.com/photos/zaragozaantigua/20689438908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21065, 'Amadeo I 1871', 'Mariano Jâ”śâ•‘dez. 1871. Imagen de Amadeo I, italiano rey de Espaâ”śâ–’a entre 1870 y 1873, realizada en el gabinete fotogrâ”śĂ­fico de Mariano Jâ”śâ•‘dez y Ortiz en el Coso, 33, â”śâ•‘ltimo piso, durante la visita Real a Zaragoza los dâ”śÂˇas 26-28 de setiembre de 1871. Fuente: "Primeros tiempos de la fotografâ”śÂˇa en Zaragoza" (2010).', 1871, 1871, 1871, 'Siglo XIX', 'CENTRO', 41.65295400, -0.88154500, '0101000020E610000068791EDC9D35ECBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15693157239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15693157239.webp', 'https://www.flickr.com/photos/zaragozaantigua/15693157239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21159, 'Palacio de Coloma 1898', 'Fachada de la antigua casa palacio de Juan de Coloma (1539), segâ”śâ•‘n proyecto de Juan de la Mica. Serâ”śĂ­ la nueva sede del Casino Mercantil y Agrâ”śÂˇcola cuando. tras su derribo en 1912, se construya un nuevo edificio con diseâ”śâ–’o de Francisco Albiâ”śâ–’ana, en el Coso 29 de Zaragoza. Fuente visual: La Revista Moderna, 26 de noviembre de 1898.', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.65267200, -0.88129900, '0101000020E61000008EEBDFF59933ECBFE9818FC18AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20035192555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20035192555.webp', 'https://www.flickr.com/photos/zaragozaantigua/20035192555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21169, 'Centro Mercantil 1898', 'Imagen capturada en el interior del Salâ”śâ”‚n de Fiestas del Centro Mercantil, Industrial y Agrâ”śÂˇcola de Zaragoza, que fuera antigua casa de Juan Coloma, y luego de los Pâ”śÂ®rez de Pomar, del conde de Guimerâ”śĂ­, del duque de Hâ”śÂˇjar, y finalmente de Azara (marquâ”śÂ®s de Nibbiano). Este esplendoroso Salâ”śâ”‚n de Fiestas, que habâ”śÂˇa sido remodelado recientemente por el maestro de obras Antonio Miranda, lucâ”śÂˇa de esta guisa antes del inicio de la Iâ”¬Â¬ Asamblea de Câ”śĂ­maras de Comercio, Industria y Navegaciâ”śâ”‚n de Espaâ”śâ–’a, bajo la presidencia de Basilio Paraâ”śÂˇso. Fuente visual: fotografâ”śÂˇa de Enrique Beltrâ”śĂ­n editada por Josep Thomas, en revista La Ilustraciâ”śâ”‚n Artâ”śÂˇstica (Barcelona).', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.65276600, -0.88151300, '0101000020E610000090F63FC05A35ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26804517708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26804517708.webp', 'https://www.flickr.com/photos/zaragozaantigua/26804517708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21172, 'Casa de Coloma 1898', 'Fachada de la antigua casa de Juan de Coloma, construida en el Coso alto durante el primer tercio del siglo XVI, segâ”śâ•‘n proyecto de Juan de la Mica. Serâ”śĂ­ la nueva sede del Casino Mercantil, Industrial y Agrâ”śÂˇcola cuando, tras su derribo, se construya un nuevo edificio con diseâ”śâ–’o de Francisco Albiâ”śâ–’ana. La imagen se ha tomado con motivo de la celebraciâ”śâ”‚n en Zaragoza de la asamblea estatal de Câ”śĂ­maras de Comercio que tuvo lugar en noviembre de 1898 en este singular espacio. Fuente visual: revista "Nuevo mundo", 30 de noviembre de 1898.', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.65255900, -0.88123500, '0101000020E6100000DEE522BE1333ECBFF0DAA50D87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30249628504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30249628504.webp', 'https://www.flickr.com/photos/zaragozaantigua/30249628504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21330, 'Calle de la Independencia 1903', 'Efâ”śÂˇmero arco triunfal patrocinado por el Ayuntamiento de Zaragoza y erigido en la calle de la Independencia con motivo de la primera visita oficial del rey Alfonso XIII. Fue el segundo de los tres arcos instalados, y contâ”śâ”‚ con el diseâ”śâ–’o del arquitecto municipal Ricardo Magdalena en el estilo neogâ”śâ”‚tico al gusto de la â”śÂ®poca con detalles ornamentales vegetales inequâ”śÂˇvocamente modernistas, destacando por su rareza el parabâ”śâ”‚lico arco central inspirado en Gaudâ”śÂˇ. Destaca el leâ”śâ”‚n del escudo zaragozano adosado a los pilares que soportan el arco, y en el centro, algunos de los tradicionales sâ”śÂˇmbolos del escudo de Aragâ”śâ”‚n. Al fondo, el arco de la Real Maestranza ubicado junto a la plaza de la Constituciâ”śâ”‚n.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65149500, -0.88178100, '0101000020E61000005F7EA7C98C37ECBFF6402B3064D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50803721857.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50803721857.webp', 'https://www.flickr.com/photos/zaragozaantigua/50803721857/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21356, 'Plaza de la Constituciâ”śâ”‚n 1900', 'Invernal escena capturada en la plaza de la Constituciâ”śâ”‚n posiblemente durante los denominados "dâ”śÂˇas del rey" en los que se conmemoraba de forma oficial el enlace en Madrid del rey Alfonso XII con la infanta Mâ”¬Â¬ de las Mercedes de Orleans el 23 de enero de 1878. Las celebraciones castrenses incluâ”śÂˇan el despliegue de bandas de mâ”śâ•‘sica de la guarniciâ”śâ”‚n en espacios como esta plaza, donde interpretaban mâ”śâ•‘sicas que pretendâ”śÂˇan amenizar a paseantes y pâ”śâ•‘blico. Por ello, en la imagen aparecen algunos militares de la guarniciâ”śâ”‚n vistiendo sus trajes de gala en esta esquina occidental de la plaza con el tramo alto del Coso, mezclados en una turbamulta donde destacan unos cuantos pardales que rodean lo que parecerâ”śÂˇa algâ”śâ•‘n tipo de espectâ”śĂ­culo callejero del que destaca una anciana subida en una silla portando un recipiente. Por contraste, resulta curiosa la presencia, a la izquierda y justo donde la esquina, de un cartel publicitario del establecimiento de Electroterapia e Hidroterapia del especialista A. Claver sito en la calle de Valencia (esquina con la calle de Canfranc) donde se trataban "segâ”śâ•‘n la ciencia" las enfermedades del sistema nervioso. Al fondo, fachada del inmueble del nâ”śâ•‘mero 31 del Coso propiedad de Cecilio Gasca que unos aâ”śâ–’os despuâ”śÂ®s serâ”śÂˇa profundamente remodelada con proyecto del arquitecto Josâ”śÂ® de Yarza Echenique. En â”śÂ®l destaca la presencia de la Academia de Comercio de Fernando Lâ”śâ”‚pez Toral, la gran Sastrerâ”śÂˇa de Francisco Pâ”śÂ®rez y el tradicional establecimiento de lustrar y charolar el calzado antes de las celebraciones sociales. A la izquierda de este inmueble, leve vista de la fachada de la que fuera originalmente gran casa de Coloma sita en el nâ”śâ•‘mero 29 del Coso.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65256100, -0.88123400, '0101000020E6100000C7F143A51133ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54781828524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54781828524.webp', 'https://www.flickr.com/photos/zaragozaantigua/54781828524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21377, 'Diputaciâ”śâ”‚n Provincial c.1910', 'Fototipia Thomas. c.1910. "Diputaciâ”śâ”‚n Provincial". Imagen de la plaza de la Constituciâ”śâ”‚n, con el original edificio de la DPZ. A su izquierda, el edificio esquinero de la plaza, con el "Cafâ”śÂ® Suizo" en sus bajos. A su derecha, el edificio esquinero con el Coso. Ambos edificios serâ”śĂ­n reformados unos aâ”śâ–’os despuâ”śÂ®s, como le sucederâ”śĂ­ a la sede de la DPZ. Fuente: www.el-trastero.eu/caddie/images/Zaragoza Capital-017.webp', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65217500, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF68226C787AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15737374610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15737374610.webp', 'https://www.flickr.com/photos/zaragozaantigua/15737374610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21395, 'Pl. de la Constituciâ”śâ”‚n 1913', 'Quiosco del Toni en la plaza de la Constituciâ”śâ”‚n. Al fondo, arranque del Coso Alto, con la sucursal del Banco Hispano Americano en la antigua Casa de las Balsas. A la derecha, vista parcial del inmueble del Coso nâ”¬â•‘ 33. Fuente visual: Foto Lorenzo Almarza, en Archivo de la Diputaciâ”śâ”‚n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65252700, -0.88122400, '0101000020E6100000E4688EACFC32ECBFE560360186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21286830268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21286830268.webp', 'https://www.flickr.com/photos/zaragozaantigua/21286830268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21514, 'Vista de Zaragoza c.1920', 'Casino Mercantil y Agrâ”śÂˇcola. Ca.1920. Decoraciâ”śâ”‚n del interior del nuevo Casino Mercantil y Agrâ”śÂˇcola inspirada en la moda Regionalista y Costumbrista del momento. En la imagen, una vista sublimada de la ciudad desde el Cabezo Cortado, uno de los parajes naturales mâ”śĂ­s frecuentados entonces para capturar buenas imâ”śĂ­genes panorâ”śĂ­micas de la ciudad. La lâ”śÂˇnea de torres de la urbe medieval, como idealizado espacio de encuentro entre el cielo y un suelo que, de puro dorado, dan ganas de sisarlo.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65270400, -0.88135300, '0101000020E61000005A68E7340B34ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15738628767.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15738628767.webp', 'https://www.flickr.com/photos/zaragozaantigua/15738628767/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21533, 'Coso Alto 1925', 'El Coso Alto, Lucien Roisin. Vista del Coso Alto de Zaragoza, desde el palacio de Sâ”śĂ­stago (izquierda, ocupado por el Banco Espaâ”śâ–’ol de Crâ”śÂ®dito) hasta su principio, al fondo, donde se ve el colegio de los Escolapios en construcciâ”śâ”‚n. Fuente: "Zaragoza, aâ”śâ–’os veinte. 81 fotografâ”śÂˇas de Roisin (1925-1931)", Instituciâ”śâ”‚n Fernando el Catâ”śâ”‚lico, 2014.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65276800, -0.88167600, '0101000020E61000000B613596B036ECBF0BF0DDE68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19471297663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19471297663.webp', 'https://www.flickr.com/photos/zaragozaantigua/19471297663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21586, 'Pl. de la Constituciâ”śâ”‚n c.1920', 'Obras en la confluencia de la plaza de la Constituciâ”śâ”‚n con el Coso Alto. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65255900, -0.88123500, '0101000020E6100000DEE522BE1333ECBFF0DAA50D87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24786999242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24786999242.webp', 'https://www.flickr.com/photos/zaragozaantigua/24786999242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21634, 'Casco Viejo 1925', 'Imagen capturada desde la recrecida altura del inmueble del nâ”¬â•‘ 1 de la plaza de la Constituciâ”śâ”‚n, esquinero con el Coso Alto, que permite esta vista con orientaciâ”śâ”‚n norteâ”śâ–’a de los tejados del Casco Viejo que cierra el templo del Pilar. En primer tâ”śÂ®rmino, luminosa terraza y palomar (a la izquierda) que culminaba de llamativa forma el modernista Centro Mercantil, Industrial y Agrâ”śÂˇcola, en el inmueble del nâ”¬â•‘ 29 del Coso Alto.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65273700, -0.88128800, '0101000020E6100000936E4BE48233ECBFD0F1D1E28CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49183083221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49183083221.webp', 'https://www.flickr.com/photos/zaragozaantigua/49183083221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21641, 'Plaza de la Constituciâ”śâ”‚n c.1923', 'Imagen capturada en la plaza de la Constituciâ”śâ”‚n y centrada en la abarrotada terraza del cafâ”śÂ® Gambrinus, con ingreso a la derecha. Fue en la dâ”śÂ®cada de los aâ”śâ–’os 80 del siglo XIX cuando en Zaragoza se fue adoptando la costumbre europea de instalar veladores en la calle como prolongaciâ”śâ”‚n de los cafâ”śÂ®s durante los meses de tiempo primaveral y veraniego.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65242400, -0.88145900, '0101000020E6100000C4793881E934ECBF11902FA182D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51115437863.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51115437863.webp', 'https://www.flickr.com/photos/zaragozaantigua/51115437863/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22182, 'P.â”¬â•‘ de Isabel la Catâ”śâ”‚lica 1956', 'Imagen capturada, posiblemente desde la altura del bloque de viviendas del nâ”¬â•‘ 1 de la plaza Emperador Carlos V, con interesante vista del entorno de la Feria de Muestras, el emboque al parque de Buenavista, y el paseo de Isabel la Catâ”śâ”‚lica, con la residencia Sanitaria Josâ”śÂ® Antonio, y el Colegio-Residencia de Nuestra Seâ”śâ–’ora del Pilar para Huâ”śÂ®rfanos e Hijos del Magisterio. Al otro lado del paseo, el convento de Jerusalâ”śÂ®n, y la obra de urbanizaciâ”śâ”‚n asociada a la construcciâ”śâ”‚n del campo municipal de La Romareda. Una unidad de la lâ”śÂˇnea 11 del tranvâ”śÂˇa se encamina hacia la plaza de Espaâ”śâ–’a, a punto de cruzarse con el tendido de la lâ”śÂˇnea 15, o Casablanca. Fuente visual: postal de Garcâ”śÂˇa Garrabella, en www.todocoleccion.net/', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63751000, -0.89841300, '0101000020E6100000D3A3A99ECCBFECBFBD6F7CED99D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31940417572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31940417572.webp', 'https://www.flickr.com/photos/zaragozaantigua/31940417572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21678, 'Pl. de Espaâ”śâ–’a 1939', 'Imagen capturada en el plaza de Espaâ”śâ–’a poco antes de la salida a primeras horas de la maâ”śâ–’ana de la I Vuelta Ciclista a Aragâ”śâ”‚n, organizada por el periâ”śâ”‚dico "Amanecer" y que con 34 corredores cubriâ”śâ”‚ siete etapas desde el 5 al 11 de octubre de 1939. Esta primera etapa se disputâ”śâ”‚ entre Zaragoza y Teruel. Los corredores llevan en el "maillot" publicidad de bicicletas "Râ”śĂ­faga", proclamada por la publicidad de la â”śÂ®poca como "La campeâ”śâ”‚n (sic) de Aragâ”śâ”‚n", porque "Râ”śĂ­faga no corre...vuela", y accesible "De venta en los principales garajes (sic) de Espaâ”śâ–’a". En este posado encontramos, desde la izquierda, al ciclista ejeano Martâ”śÂˇn Abadâ”śÂˇa Cativiela, alias "Piriro"; al vizcaâ”śÂˇno Federico Ezquerra Alonso; al bilbilitano de adopciâ”śâ”‚n Benito Cabestrero Rodrâ”śÂˇguez; al aragonâ”śÂ®s Josâ”śÂ® Lahoz Trol, conocido como "el Leâ”śâ”‚n de Marâ”śÂˇa" pues aunque naciâ”śâ”‚ en Azuara era marihuervano de adopciâ”śâ”‚n; el catalâ”śĂ­n Mariano Caâ”śâ–’ardo Lacasta y el gallego Delio Rodrâ”śÂˇguez Barros a la derecha. De fondo y a la izquierda, el Cafâ”śÂ® Gambrinus, y casi ya haciendo esquina con el Coso, La Joyita, y Bombonerâ”śÂˇa Murga. En el centro de la imagen, el edificio sede de la aseguradora La Patria Hispana, la sucursal del Banco de Bilbao y el Estudio Fotogrâ”śĂ­fico Skogler.', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.65223200, -0.88128200, '0101000020E61000000BB6114F7633ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14853150812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14853150812.webp', 'https://www.flickr.com/photos/zaragozaantigua/14853150812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21693, 'P.â”¬â•‘ de la Independencia 1931', 'Carrozas pasando por delante del bar restaurante La Maravilla, en el paseo de la Independencia, en direcciâ”śâ”‚n a la plaza de la Constituciâ”śâ”‚n, durante las fiestas del Pilar del primer aâ”śâ–’o de la Segunda Repâ”śâ•‘blica. Fuente visual: archivo Heraldo de Aragâ”śâ”‚n, en "Padre Ebro. El râ”śÂˇo Ebro y el siglo XX".', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65158400, -0.88130400, '0101000020E6100000FFAF3A72A433ECBF664CC11A67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15086553182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15086553182.webp', 'https://www.flickr.com/photos/zaragozaantigua/15086553182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21694, 'Pl. de la Constituciâ”śâ”‚n 1930', 'La Sublevaciâ”śâ”‚n de Jaca de diciembre de 1930 fue un pronunciamiento militar republicano contra el râ”śÂ®gimen de la Restauraciâ”śâ”‚n monâ”śĂ­rquica de Alfonso XIII, cuando el general Dâ”śĂ­maso Berenguer era presidente del Gobierno. Tras la declaraciâ”śâ”‚n del Estado de Guerra, fue militarmente desbaratada y fusilados sus cabecillas, los capitanes Fermâ”śÂˇn Galâ”śĂ­n Rodrâ”śÂˇguez y â”śĂĽngel Garcâ”śÂˇa Hernâ”śĂ­ndez. En Zaragoza tuvo lugar el acuartelamiento de los regimientos de infanterâ”śÂˇa Infante, Aragâ”śâ”‚n y Gerona, y los de caballerâ”śÂˇa Castillejos y Lanceros del Rey. Por ella transitaron, camino de Jaca, fuerzas de la Guardia Civil y los batallones Saboya, Lanzarote, Reus y Estella del ejâ”śÂ®rcito. Ademâ”śĂ­s, parejas de la Guardia Civil, Seguridad e Infanterâ”śÂˇa patrullaron calles y accesos, y custodiaron edificios oficiales como en la imagen, donde un retâ”śÂ®n de guardiaciviles a caballo guarda el edificio de la Diputaciâ”śâ”‚n Provincial en la plaza de la Constituciâ”śâ”‚n.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65200800, -0.88146300, '0101000020E61000001F4AB4E4F134ECBF7D5D86FF74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15147164159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15147164159.webp', 'https://www.flickr.com/photos/zaragozaantigua/15147164159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21706, 'Pl. de Espaâ”śâ–’a 1938', 'En otro de sus paseos por la ciudad, un miembro de la alemana Legiâ”śâ”‚n Câ”śâ”‚ndor captura una instantâ”śĂ­nea ciudadana recurrente, en este caso, una imagen parcial de la reciâ”śÂ®n denominada "plaza de Espaâ”śâ–’a". El aâ”śâ–’o anterior, 1937, "II aâ”śâ–’o triunfal", se cambiâ”śâ”‚ el nombre de la plaza, de "Constituciâ”śâ”‚n" (para quâ”śÂ®), a "Espaâ”śâ–’a", como reza la placa instalada en la fachada de la DPZ (que perdura), en "recuerdo perenne de su lealtad a la Patria y de su amor a la ciudad con motivo del glorioso Alzamiento Nacional contra el comunismo". Se trata de la esquina de la plaza con el Coso Alto, con la sede de Radio Zaragoza allâ”śÂˇ ubicada. A la izquierda, el edificio de la DPZ.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65270400, -0.88135300, '0101000020E61000005A68E7340B34ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16000268962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16000268962.webp', 'https://www.flickr.com/photos/zaragozaantigua/16000268962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21720, 'Pl. de la Constituciâ”śâ”‚n 1930', 'Foto Gaspar. Vista de la plaza de la Constituciâ”śâ”‚n. Preside la imagen el edificio de Miguel â”śĂĽngel Navarro esquina con el paseo de la Independencia, que estuvo en pie con ese aspecto entre 1916 y 1940. A su derecha, la Diputaciâ”śâ”‚n Provincial. Fuente: La Esfera, 29 de noviembre de 1930.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65200800, -0.88146300, '0101000020E61000001F4AB4E4F134ECBF7D5D86FF74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20041643101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20041643101.webp', 'https://www.flickr.com/photos/zaragozaantigua/20041643101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21730, 'Limpiabotas aâ”śâ–’os 30', 'Varios limpiabotas aprovechan la sombra de los pilares de los porches del paseo de la Independencia para hacer su trabajo. Al fondo, la plaza de la Constituciâ”śâ”‚n. Fuente: Archivo Heraldo de Aragâ”śâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65171000, -0.88170700, '0101000020E6100000CCEF3499F136ECBFF33CB83B6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21219972713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21219972713.webp', 'https://www.flickr.com/photos/zaragozaantigua/21219972713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21753, 'Pl. de la Constituciâ”śâ”‚n 1930', 'Vista del edificio del paseo de la Independencia 2, construido por Miguel â”śĂĽngel Navarro en 1916 (reformado por el mismo arquitecto en 1940); y de la sede de la Diputaciâ”śâ”‚n Provincial de Zaragoza, en la plaza de la Constituciâ”śâ”‚n 2, levantado en 1858 segâ”śâ•‘n proyecto de Pedro Martâ”śÂˇnez Sangrâ”śâ”‚s (remodelado por Teodoro Râ”śÂˇos entre 1945 y 1952). El tranvâ”śÂˇa pertenece a la lâ”śÂˇnea 5 (Torrero). Fuente visual: Colecciâ”śâ”‚n Francisco Boisset.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65187800, -0.88131000, '0101000020E610000088687407B133ECBFAF7D01BD70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22231235892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22231235892.webp', 'https://www.flickr.com/photos/zaragozaantigua/22231235892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
